#include <stdio.h>
#include <string.h>

typedef struct {
    char model[51];
    int year;
} Car;

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    getchar(); // consume newline after T
    for(int tc=0; tc<T; ++tc){
        Car c1,c2;
        fgets(c1.model, sizeof(c1.model), stdin);
        c1.model[strcspn(c1.model, "\n")] = '\0';
        scanf("%d", &c1.year);
        getchar(); // consume newline after year
        fgets(c2.model, sizeof(c2.model), stdin);
        c2.model[strcspn(c2.model, "\n")] = '\0';
        scanf("%d", &c2.year);
        getchar(); // consume newline after year
        printf("Car 1: Model = %s, Year = %d\n", c1.model, c1.year);
        printf("Car 2: Model = %s, Year = %d", c2.model, c2.year);
        if(tc!=T-1) printf("\n");
    }
    return 0;
}

