code.Java:
import java.io.*;
public class Main{
    static class Car{String model;int year;Car(String m,int y){model=m;year=y;}}
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder sb=new StringBuilder();
        for(int tc=0; tc<T; ++tc){
            String model1=br.readLine();
            int year1=Integer.parseInt(br.readLine().trim());
            String model2=br.readLine();
            int year2=Integer.parseInt(br.readLine().trim());
            sb.append("Car 1: Model = ").append(model1).append(", Year = ").append(year1).append('\n');
            sb.append("Car 2: Model = ").append(model2).append(", Year = ").append(year2);
            if(tc!=T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

